                                let allSlides = Array.from(container.querySelectorAll(".banner-slide"));
                                if (allSlides.length === 0) return;
                                const hasNotifications = "Notification" in window && (Notification.permission === "granted" || Notification.permission === "denied");
                                const hasProfile = localStorage.getItem("profileCompleted") === "true" || window.currentUser && window.currentUser.displayName && window.currentUser.displayName !== "Guest";
                                let vocabCount = 0;
                                try {
                                    const localVocab = localStorage.getItem("enghelper_vocab");
                                    if (localVocab) vocabCount = JSON.parse(localVocab).length;
                                } catch (e) {
                                }
                                const isNewUser = vocabCount < 5;
                                let filteredSlides = allSlides.filter((slide) => {
                                    const action = slide.dataset.action;
                                    if (action === "enable-notifications" && hasNotifications) return false;
                                    if (action === "edit-profile" && hasProfile) return false;
                                    if (action === "learning-insights") {
                                        const today = new Date();
                                        const day = today.getDay();
                                        const date = today.getDate();
                                        const lastDayOfMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0).getDate();
                                        const isWeekend = day === 0 || day === 5 || day === 6;
                                        const isEndOfMonth = date >= lastDayOfMonth - 2;
                                        if (!isWeekend && !isEndOfMonth) return false;
                                    }
                                    return true;
                                });
                                let highPriority = [];
                                let normalPriority = [];
                                filteredSlides.forEach((slide) => {
                                    const action = slide.dataset.action;
                                    if (isNewUser) {
                                        if (["edit-profile", "open-settings", "enable-notifications", "use-spotlight"].includes(action)) {
                                            highPriority.push(slide);
                                        } else {
                                            normalPriority.push(slide);
                                        }
                                    } else {
                                        if (["popup-quiz", "review-weakness", "smart-streak", "grammar-tip"].includes(action)) {
                                            highPriority.push(slide);
                                        } else {
                                            normalPriority.push(slide);
                                        }
                                    }
                                });
                                highPriority.sort(() => Math.random() - 0.5);
                                normalPriority.sort(() => Math.random() - 0.5);
                                let finalSlides = [...highPriority, ...normalPriority];
                                container.innerHTML = "";
                                finalSlides.forEach((slide, index) => {
                                    slide.classList.remove("active");
                                    if (index === 0) slide.classList.add("active");
                                    container.appendChild(slide);
                                });
