                            function wrapWordsInNode(parentNode) {
                                Array.from(parentNode.childNodes).forEach((childNode) => {
                                    if (childNode.nodeType === Node.TEXT_NODE) {
                                        const text = childNode.nodeValue;
                                        const words = text.split(/(\s+|(?<=\w)(?=[^\w\s])|(?<=[^\w\s])(?=\w))/);
                                        const fragment = document.createDocumentFragment();
                                        words.forEach((wordSegment) => {
                                            if (wordSegment.trim().length > 0 && !/^\s+$/.test(wordSegment) && /\w/.test(wordSegment)) {
                                                const span = document.createElement("span");
                                                span.className = "story-clickable-word";
                                                span.textContent = wordSegment;
                                                fragment.appendChild(span);
                                            } else {
                                                fragment.appendChild(document.createTextNode(wordSegment));
                                            }
                                        });
                                        parentNode.replaceChild(fragment, childNode);
                                    } else if (childNode.nodeType === Node.ELEMENT_NODE) {
                                        if (childNode.tagName === "B") {
                                            childNode.classList.add("story-clickable-word");
                                        } else if (!childNode.classList.contains("translation-text")) {
                                            wrapWordsInNode(childNode);
                                        }
                                    }
                                });
                            }
