                                    const detailBase = hist.explanation_th || hist.concept_th || hist.key_takeaway || "\u0E40\u0E1B\u0E34\u0E14\u0E40\u0E1E\u0E37\u0E48\u0E2D\u0E17\u0E1A\u0E17\u0E27\u0E19\u0E1A\u0E17\u0E40\u0E23\u0E35\u0E22\u0E19\u0E19\u0E35\u0E49\u0E2D\u0E35\u0E01\u0E04\u0E23\u0E31\u0E49\u0E07";
