                                    const timestampLabel = story.lastOpenedAt && story.lastOpenedAt !== story.createdAt ? `\u0E40\u0E1B\u0E34\u0E14\u0E25\u0E48\u0E32\u0E2A\u0E38\u0E14 ${formatFeatureHistoryDate(story.lastOpenedAt)}` : formatFeatureHistoryDate(story.createdAt);
