                                        if (isSynonymOfNew) statusBadges.push(`<span class="status-badge synonym-new">\u0E40\u0E1E\u0E34\u0E48\u0E21\u0E40\u0E1B\u0E47\u0E19\u0E04\u0E33\u0E1E\u0E49\u0E2D\u0E07\u0E02\u0E2D\u0E07 "${isSynonymOfNew}"</span>`);
