                            function populateDialectFormFields(dialects, wordDialects) {
                                // 1. Populate spelling and phonetic inputs
                                if (dialects && typeof dialects === "object") {
                                    Object.keys(dialects).forEach(d => {
                                        const info = dialects[d];
                                        if (info) {
                                            const code = d.toLowerCase();
                                            const spellingInput = document.getElementById(`dialog-dialect-spelling-${code}`);
                                            const phoneticInput = document.getElementById(`dialog-dialect-phonetic-${code}`);
                                            if (spellingInput) spellingInput.value = info.spelling || '';
                                            if (phoneticInput) phoneticInput.value = info.phonetic || '';
                                        }
                                    });
                                }

                                // 2. Determine active dialects
                                let activeList = [];
                                if (Array.isArray(wordDialects) && wordDialects.length > 0) {
                                    activeList = wordDialects;
                                } else if (dialects && typeof dialects === "object") {
                                    // Fallback: active dialects are those with spelling or phonetic info
                                    activeList = Object.keys(dialects).filter(d => dialects[d] && (dialects[d].spelling || dialects[d].phonetic));
                                }

                                if (activeList.length === 0) {
                                    activeList = ["General"];
                                }

                                // 3. Check checkboxes and show/expand accordions for active dialects
                                activeList.forEach(d => {
                                    const code = d.toLowerCase();
                                    const checkbox = document.querySelector(`input[name="dialog-dialects-check"][value="${d.toUpperCase()}"]`);
                                    if (checkbox) {
                                        checkbox.checked = true;
                                        const btnLabel = checkbox.closest('.dialect-checkbox-btn');
                                        if (btnLabel) {
                                            btnLabel.style.background = 'var(--primary-color)';
                                            btnLabel.style.borderColor = 'var(--primary-color)';
                                            btnLabel.style.color = 'white';
                                        }
                                    }
                                    const accordionItem = document.querySelector(`.dialect-accordion-item.${code}`);
                                    if (accordionItem) {
                                        accordionItem.style.display = 'block';
                                        const content = accordionItem.querySelector('.dialect-accordion-content');
                                        const icon = accordionItem.querySelector('.dialect-accordion-header i');
                                        if (content) content.style.display = 'flex';
                                        if (icon) icon.style.transform = 'rotate(180deg)';
                                    }
                                });
                            }

