                            function getCleanedText(text) {
                                return text.toLowerCase().replace(/[^\w\s]|_/g, "").replace(/\s+/g, " ").trim();
                            }
                            function calculateLevenshteinDistance(a, b) {
                                const matrix = [];
                                let i, j;
                                if (a.length === 0) return b.length;
                                if (b.length === 0) return a.length;
                                for (i = 0; i <= b.length; i++) {
                                    matrix[i] = [i];
                                }
                                for (j = 0; j <= a.length; j++) {
                                    matrix[0][j] = j;
                                }
                                for (i = 1; i <= b.length; i++) {
                                    for (j = 1; j <= a.length; j++) {
                                        if (b.charAt(i - 1) === a.charAt(j - 1)) {
                                            matrix[i][j] = matrix[i - 1][j - 1];
                                        } else {
                                            matrix[i][j] = Math.min(matrix[i - 1][j - 1] + 1, Math.min(matrix[i][j - 1] + 1, matrix[i - 1][j] + 1));
                                        }
                                    }
                                }
                                return matrix[b.length][a.length];
                            }
                            function getSimilarityPercentage(original, recognized) {
                                const cleanOriginal = getCleanedText(original);
                                const cleanRecognized = getCleanedText(recognized);
                                if (cleanOriginal === cleanRecognized) return 100;
                                if (cleanOriginal.length === 0 || cleanRecognized.length === 0) return 0;
                                const distance = calculateLevenshteinDistance(cleanOriginal, cleanRecognized);
                                const maxLength = Math.max(cleanOriginal.length, cleanRecognized.length);
                                const percentage = (maxLength - distance) / maxLength * 100;
                                return Math.max(0, Math.round(percentage));
                            }
