                                    const prompt = `Provide a very concise Thai translation or explanation for the English word: "${word}"`;
                                    const payload = { contents: [{ parts: [{ text: prompt }] }] };
                                    const aiData = await callGemini(payload, aiRolePlayDialogLoading, null, { contextScope: "roleplay" });
